import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"无线路由器小抄","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/无线路由器/无线路由器小抄.md","filePath":"ccc/无线路由器/无线路由器小抄.md"}`),a={name:`ccc/无线路由器/无线路由器小抄.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="无线路由器小抄" tabindex="-1">无线路由器小抄 <a class="header-anchor" href="#无线路由器小抄" aria-label="Permalink to “无线路由器小抄”">​</a></h1><p>更新于2022.5.4</p><ul><li>再贵的路由器都不会有多大的覆盖范围和穿墙能力，双拳难敌四手，要覆盖大信号好只能多买几台组mesh。</li><li>手机，网卡基本是2x2设备，连上4x4方案的路由，理论最大速率要除以2。</li><li>水星是tplink马甲，基本是一样的主板，水星便宜买水星就好了。</li><li>推荐的通常越高价位无线质量越好，但是300以上的路由器提升幅度显著下降。</li><li>小米原厂固件对旁路由支持有问题。</li><li>同价位排在越靠前说明越推荐。</li></ul><h2 id="_100以内-能用就行" tabindex="-1">100以内-能用就行 <a class="header-anchor" href="#_100以内-能用就行" aria-label="Permalink to “100以内-能用就行”">​</a></h2><ul><li><strong>水星D121G</strong><code>MESH</code>￥79</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>3千兆网口WIFI5   mt7628(单核0.6mips)</span></span>
<span class="line"><span>2.4g-主芯片集成-40mhz-64QAM(2×2)(300m)</span></span>
<span class="line"><span>5g	 -mt7612 -80mhz-256QAM(2×2)(867m)</span></span></code></pre></div><blockquote><p>  同价位最中庸，功能都有，体验一般。同方案有千兆变百兆的水星d121（3百兆网口）和水星d12（4百兆网口）还能再便宜几块钱。虽然能组mesh，但不推荐。</p></blockquote><ul><li>【二手】 <strong>天邑TY300</strong><code>MESH</code>闲鱼￥79 <code>运营商定制</code></li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>5千兆网口WIFI6  128MB  BCM6750(三核1.5a7)+散热片</span></span>
<span class="line"><span>2.4g-bcm43217+外置功放-40mhz-64QAM(2×2)(300m)</span></span>
<span class="line"><span>5g	 -主芯片集成+外置功放-80mhz-1024QAM(2×2)(1.2g)</span></span></code></pre></div><blockquote><p>  同价位mesh首选。非常划算，这个方案虽然信号一般，但是架不住便宜。</p><p>  同方案的ty400有usb3.0，3个千兆口。</p><p>   TY6201A是bcm6755方案，价格有点高，等降价。</p></blockquote><ul><li><strong>【二手】小米路由器mini</strong> ￥30</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>3千兆网口WIFI5   mt7620(单核0.6mips)+散热板+第三方固件</span></span>
<span class="line"><span>2.4g-mt7603+外置LNA+屏蔽罩-40mhz-64QAM(2×2)(300m)</span></span>
<span class="line"><span>5g	 -mt7612e+屏蔽罩     -80mhz-256QAM(2×2)(867m)</span></span></code></pre></div><blockquote><p>  体验还可以最便宜的路由器，有5Ghz，同方案中做工精良，还有USB口。</p></blockquote><ul><li><strong>【二手】中兴E8820 V2</strong>【48元】<code>64MBram</code><code>散热片</code><code>USB2</code><ul><li><strong>友华wr1200js</strong><code>128MBram</code><code>USB2</code></li><li><strong>newifi 3</strong><code>512MBram</code><code>屏蔽罩</code><code>散热板</code><code>USB3</code></li></ul></li></ul><p><code>mt7621(双核mips0.8)</code><code>mt7603(2.4g)+mt7612e(5g)</code><code>5千兆网口</code><code>三方固件</code></p><blockquote><p>  最便宜千兆无线路由器，同价位有线转发性能最强。</p><p>  中兴E8820 V2刷机需要TTL或编程器。</p><p>  友华wr1200js贵一点但是有128MBram，刷机方便。</p><p>  newifi 3 做工好，刷机方便，但是漏油，甚至导致无线搜不到。</p><p>  如果跑应用的话，arm架构性能更强，30块的电视盒r3300L，100块的斐讯n1，70块的我家云都是不错的选择。</p></blockquote><h2 id="_100-200主流价位" tabindex="-1">100-200主流价位 <a class="header-anchor" href="#_100-200主流价位" aria-label="Permalink to “100-200主流价位”">​</a></h2><p>  这个价位还有二手老旗舰可以买，比同价位一手强，参见页尾二手。</p><ul><li><strong>红米AC2100</strong><code>刷机MESH</code>日常￥169史低￥134</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>4千兆网口WIFI5      mt7621(双核0.8mips)+散热板+第三方固件</span></span>
<span class="line"><span>2.4g-mt7603+外置功放+屏蔽罩-40mhz-64QAM(2×2)(300m)</span></span>
<span class="line"><span>5g	-mt7615		    +屏蔽罩-80mhz-256QAM(4×4)(1.7g)</span></span></code></pre></div><blockquote><p>  同价位最明智的选择，红米ax5，小米ax1800的5Ghz都不如这款，主要短板就是2.4g很一般。原厂固件有智能QOS和游戏优先转发，能刷三方固件。</p></blockquote><ul><li><strong>水星D191g</strong> <code>MESH</code> ￥119</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>3千兆网口WIFI5   TP1900BN+散热片</span></span>
<span class="line"><span>2.4g-MT7761N-40mhz-256QAM(3×3)(600m)</span></span>
<span class="line"><span>5g	-MT7762N-80mhz-256QAM(3×3)(1.3g)</span></span></code></pre></div><blockquote><p>  wdr7660千兆版马甲，组mesh体验不错最便宜的一手路由器。水星D191G，D196G，D19G三个型号同一个方案，D196G多一个网口。</p></blockquote><h2 id="_200-300" tabindex="-1">200-300 <a class="header-anchor" href="#_200-300" aria-label="Permalink to “200-300”">​</a></h2><ul><li><p>红米AX6S（联发科4x4）</p><p>TP-Link xdr3010（高通2x2）</p></li></ul><p>红米固件功能多一点。tplink便宜一点，家用感知差不多。</p><p>但是我个人认为上这个价位不如再加一点，红米AX5400千兆版，板子做工设计看齐旗舰。</p><h2 id="_300" tabindex="-1">300+ <a class="header-anchor" href="#_300" aria-label="Permalink to “300+”">​</a></h2><p>  贵价路由确实都很不错，但普通家用场景中，性能提升其实很小，性价比不高。与高价路由器的4x4mimo感知不明显密不可分。</p><p>红米ax5400千兆版，板子做工设计看齐旗舰，相当实惠。</p><ul><li><strong>TP-LINK XDR6030</strong> <code>MESH</code> ￥599</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>4千兆WIFI6 -512MBram-BCM4906(双核1.8a53）+屏蔽罩+散热板+法拉第笼</span></span>
<span class="line"><span>2.4g-BCM43684+外置功放+屏蔽罩-40mhz-1024QAM(4×4)(1174m)</span></span>
<span class="line"><span>5g	-BCM43684+外置功放+屏蔽罩-160mhz-1024QAM(4×4)(4.8g)</span></span></code></pre></div><blockquote><p>  博通旗舰方案，做AP非常顶，唯一缺点就是tp-link固件功能缺缺。80块买个N1刷openwrt做旁路由， tp这款做ap，性价比爆炸，就是比较麻烦。</p></blockquote><ul><li><strong>TP-LINK XDR6060</strong> <code>MESH</code> ￥1480</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>3千兆+2.5g网口WIFI6 -1GBram-BCM4908(四核1.8a53）+屏蔽罩+散热板+法拉第笼</span></span>
<span class="line"><span>2.4g-BCM43684+外置功放+屏蔽罩-40mhz-1024QAM(4×4)(1174m)</span></span>
<span class="line"><span>5g	-BCM43684+外置功放+屏蔽罩-160mhz-1024QAM(4×4)(4.8g)</span></span></code></pre></div><blockquote><p>  博通旗舰方案，能刷梅林。价格也水涨船高。ax88u同方案，tp这款还多了2.5g口。刷梅林首选这款。</p></blockquote><ul><li>TP-LINK XTR5460</li></ul><blockquote><p>  重度手游玩家可以考虑，相对比较便宜的三频ax路由，两个5g可以分一个专门用在打游戏上。</p></blockquote><h2 id="梅林" tabindex="-1">梅林 <a class="header-anchor" href="#梅林" aria-label="Permalink to “梅林”">​</a></h2><p>  梅林最大的优势是开箱即用，够傻瓜。非刷梅林不可才考虑这几款，性价比都一般。</p><ul><li><p>首推前文介绍的TP-LINK XDR6060，ax88u同方案还多了2.5g网口。</p></li><li><p>其次等ax68u降价。相对ax88u阉割成双频3x3，但是刚上市价格虚高。</p></li><li><p>不在乎性价比，ax86u相对ax88u，2.4g阉割成3x3，多了一个2.5g网口，不过只有ap模式能当LAN口用，不然只能当wan口用。</p></li><li><p>一个字，坑。TUF AX3000 相对ax86u，cpu阉割成bcm6750，三核a7，2.4g集成在cpu当中，表现一般，5g通过软件限制成2t4r，而开启4t4r的ax82u卖高价，但是ax3000刷梅林能解锁成4t4r。注意梅林后续重心在a53架构上，这个有点尴尬。</p></li><li><p>ax56u双频全集成2x2，无线连华为ax3pro都干不过。除了能刷梅林，一无是处。</p></li><li><p>AX92U是三频路由器，有两颗5g芯片，一颗ac2x2,一颗ax4x4。贵的一逼。</p></li><li><p>AX6600M 三频路由器，相对ax92u，ac2x2升级成ax2x2，还有2.5g网口。贵的一逼。</p></li></ul><h2 id="二手" tabindex="-1">二手 <a class="header-anchor" href="#二手" aria-label="Permalink to “二手”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>注意，电子产品随着年限，不可避免地电气性能会有下降，二手路由器的表现层次不齐。</span></span></code></pre></div><ul><li>博通方案：华硕ac68u,ac66u；Linksys EA6700 腾达ac15(硬改刷梅林)ac18(刷cfe后刷梅林) 网件r7000</li></ul><p>  这几个老将现在基本降到100出头。能刷梅林。博通制程落后，发热功耗都高一个等级。</p><ul><li>mt7615方案：dlink-dir878,882（882带usb），华硕ac85u,ac85p，JCG-AC860M（jcg这个做工很不错），小米路由器3PRO（无外置功放）</li></ul><p>  这些能刷padavan开启160mhz。我的体验是mt7615无线质量比老博通强。</p>`,48)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};